mapper.insert:
    	INSERT /* @SQLID=SUB0202_0303-03_1#Sql001 */ INTO FOREIGN_CONSIGNMENT_ORDER (
			 IFA_ORDER_NO
			,IFA_ORDER_SUB_NO
			,ACCEPT_ORDER_NO
			,ACCEPT_ORDER_SUB_NO
			,BUTEN_CODE
			,ACCOUNT_NUMBER
			,BRAND_CODE
			,BRAND_NAME
			,EXCHANGE_CODE
			,METHOD_TYPE
			,TRADE_TYPE
			,ORDER_QUANTITY
			,TRADE_METHOD_TYPE
			,LIMIT_PRICE
			,STOP_PRICE
			,CURRENCY_CODE
			,SETTLEMENT_TYPE
			,DEPOSIT_TYPE
			,INVITATION_TYPE
			,ORDER_METHOD_TYPE
			,WARNING_APPLY_TYPE
			,EXPLANATION_INFO_TYPE
			,TRANSFER_INVITATION_TYPE
			,ENG_PUB_BRAND_EXP_TYPE
			,CONFIRMATION_TYPE
			,ORDER_TYPE
			,ORDER_DATE
			,ORDER_TIME
			,TRADE_DATE
			,TRADE_LIMIT_DATE
			,BROKER_CODE
			,INTERMEDIARY_EMP_CD
			,API_ERROR_CODE
			,API_STATUS_CODE
			,API_MESSAGE
			,CREATE_TIME
			,CREATE_USER
			,UPDATE_TIME
			,UPDATE_USER
		)
		VALUES(
			 #{req.ifaOrderNo}				
			,#{req.ifaOrderSubNo}				
			,#{req.acceptOrderNo}				
			,#{req.acceptOrderSubNo}			
			,#{req.butenCode}					
			,#{req.accountNumber}				
			,#{req.brandCode}					
			,#{req.brandName}					
			,#{req.exchangeCode}				
			,#{req.methodType}				
			,#{req.tradeType}					
			,#{req.orderQuantity}				
			,#{req.tradeMethodType}			
			,#{req.limitPrice}				
			,#{req.stopPrice}					
			,#{req.currencyCode}				
			,#{req.settlementType}			
			,#{req.depositType}				
			,#{req.invitationType}			
			,#{req.orderMethodType}			
			,null							
			,#{req.explanationInfoType}		
			,null							
			,#{req.engPubBrandExpType}		
			,'1'							
			,'2'							
			,#{req.orderDate}					
			,TO_TIMESTAMP(#{req.orderTime},'YYYY/MM/DD HH24:MI:SS')					
			,#{req.tradeDate}					
			,#{req.tradeLimitDate}			
			,#{req.brokerCode}				
			,#{req.intermediaryEmpCd}			
			,null                			
			,null							
			,null							
			,SYSDATE							
			,#{req.createUser}				
			,SYSDATE							
			,#{req.updateUser}				
		)
